@Override
    public Set<Timeout> stop() {
        if (Thread.currentThread() == workerThread) {
            throw new IllegalStateException(
                HashedWheelTimer.class.getSimpleName() +
                    ".stop() cannot be called from " +
                    TimerTask.class.getSimpleName());
        }

        if (!WORKER_STATE_UPDATER.compareAndSet(this, WORKER_STATE_STARTED, WORKER_STATE_SHUTDOWN)) {
            // workerState can be 0 or 2 at this moment - let it always be 2.
            if (WORKER_STATE_UPDATER.getAndSet(this, WORKER_STATE_SHUTDOWN) != WORKER_STATE_SHUTDOWN) {
                INSTANCE_COUNTER.decrementAndGet();
            }

            return Collections.emptySet();
        }

        try {
            boolean interrupted = false;
            while (workerThread.isAlive()) {
                workerThread.interrupt();
                try {
                    workerThread.join(100);
                } catch (InterruptedException ignored) {
                    interrupted = true;
                }
            }

            if (interrupted) {
                Thread.currentThread().interrupt();
            }
        } finally {
            INSTANCE_COUNTER.decrementAndGet();
        }
        return worker.unprocessedTimeouts();
    }

@Override
    public Timeout newTimeout(TimerTask task, long delay, TimeUnit unit) {
        if (task == null) {
            throw new NullPointerException("task");
        }
        if (unit == null) {
            throw new NullPointerException("unit");
        }

        long pendingTimeoutsCount = pendingTimeouts.incrementAndGet();

        if (maxPendingTimeouts > 0 && pendingTimeoutsCount > maxPendingTimeouts) {
            pendingTimeouts.decrementAndGet();
            throw new RejectedExecutionException("Number of pending timeouts ("
                + pendingTimeoutsCount + ") is greater than or equal to maximum allowed pending "
                + "timeouts (" + maxPendingTimeouts + ")");
        }

        start();

        // Add the timeout to the timeout queue which will be processed on the next tick.
        // During processing all the queued HashedWheelTimeouts will be added to the correct HashedWheelBucket.
        long deadline = System.nanoTime() + unit.toNanos(delay) - startTime;

        // Guard against overflow.
        if (delay > 0 && deadline < 0) {
            deadline = Long.MAX_VALUE;
        }
        HashedWheelTimeout timeout = new HashedWheelTimeout(this, task, deadline);
        timeouts.add(timeout);
        return timeout;
    }

protected int getWeight(Invoker<?> invoker, Invocation invocation) {
    int weight;
    URL url = invoker.getUrl();
    if (invoker instanceof ClusterInvoker) {
        url = ((ClusterInvoker<?>) invoker).getRegistryUrl();
    }

    // Multiple registry scenario, load balance among multiple registries.
    if (REGISTRY_SERVICE_REFERENCE_PATH.equals(url.getServiceInterface())) {
        weight = url.getParameter(WEIGHT_KEY, DEFAULT_WEIGHT);
    } else {
        weight = url.getMethodParameter(RpcUtils.getMethodName(invocation), WEIGHT_KEY, DEFAULT_WEIGHT);
        if (weight > 0) {
            long timestamp = invoker.getUrl().getParameter(TIMESTAMP_KEY, 0L);
            if (timestamp > 0L) {
                long uptime = System.currentTimeMillis() - timestamp;
                if (uptime < 0) {
                    return 1;
                }
                int warmup = invoker.getUrl().getParameter(WARMUP_KEY, DEFAULT_WARMUP);
                if (uptime > 0 && uptime < warmup) {
                    weight = calculateWarmupWeight((int) uptime, warmup, weight);
                }
            }
        }
    }
    return Math.max(weight, 0);
}

public void destroy() {
    if (!destroyed.compareAndSet(false, true)) {
        return;
    }
    // destroy raw extension instance
    extensionInstances.forEach((type, instance) -> {
        if (instance instanceof Disposable) {
            Disposable disposable = (Disposable) instance;
            try {
                disposable.destroy();
            } catch (Exception e) {
                logger.error(COMMON_ERROR_LOAD_EXTENSION, "", "", "Error destroying extension " + disposable, e);
            }
        }
    });
    extensionInstances.clear();

    // destroy wrapped extension instance
    for (Holder<Object> holder : cachedInstances.values()) {
        Object wrappedInstance = holder.get();
        if (wrappedInstance instanceof Disposable) {
            Disposable disposable = (Disposable) wrappedInstance;
            try {
                disposable.destroy();
            } catch (Exception e) {
                logger.error(COMMON_ERROR_LOAD_EXTENSION, "", "", "Error destroying extension " + disposable, e);
            }
        }
    }
    cachedInstances.clear();
}

public boolean excludeField(Field field, boolean serialize) {
  if ((modifiers & field.getModifiers()) != 0) {
    return true;
  }

  if (version != Excluder.IGNORE_VERSIONS
      && !isValidVersion(field.getAnnotation(Since.class), field.getAnnotation(Until.class))) {
    return true;
  }

  if (field.isSynthetic()) {
    return true;
  }

  if (requireExpose) {
    Expose annotation = field.getAnnotation(Expose.class);
    if (annotation == null || (serialize ? !annotation.serialize() : !annotation.deserialize())) {
      return true;
    }
  }

  if (excludeClass(field.getType(), serialize)) {
    return true;
  }

  List<ExclusionStrategy> list = serialize ? serializationStrategies : deserializationStrategies;
  if (!list.isEmpty()) {
    FieldAttributes fieldAttributes = new FieldAttributes(field);
    for (ExclusionStrategy exclusionStrategy : list) {
      if (exclusionStrategy.shouldSkipField(fieldAttributes)) {
        return true;
      }
    }
  }

  return false;
}

public static String lenientFormat(
    @Nullable String template, @Nullable Object @Nullable ... args) {
  template = String.valueOf(template); // null -> "null"

  if (args == null) {
    args = new Object[] {"(Object[])null"};
  }

  // start substituting the arguments into the '%s' placeholders
  StringBuilder builder = new StringBuilder(template.length() + 16 * args.length);
  int templateStart = 0;
  int i = 0;
  while (i < args.length) {
    int placeholderStart = template.indexOf("%s", templateStart);
    if (placeholderStart == -1) {
      break;
    }
    builder.append(template, templateStart, placeholderStart);
    builder.append(lenientToString(args[i++]));
    templateStart = placeholderStart + 2;
  }
  builder.append(template, templateStart, template.length());

  // if we run out of placeholders, append the extra args in square brackets
  if (i < args.length) {
    String prefix = " [";
    for (; i < args.length; i++) {
      builder.append(prefix);
      builder.append(lenientToString(args[i]));
      prefix = ", ";
    }
    builder.append(']');
  }

  return builder.toString();
}

public static String nullSafeToString(@Nullable Object obj) {
	if (obj == null) {
		return "null";
	}

	try {
		if (obj.getClass().isArray()) {
			if (obj.getClass().getComponentType().isPrimitive()) {
				if (obj instanceof boolean[] booleans) {
					return Arrays.toString(booleans);
				}
				if (obj instanceof char[] chars) {
					return Arrays.toString(chars);
				}
				if (obj instanceof short[] shorts) {
					return Arrays.toString(shorts);
				}
				if (obj instanceof byte[] bytes) {
					return Arrays.toString(bytes);
				}
				if (obj instanceof int[] ints) {
					return Arrays.toString(ints);
				}
				if (obj instanceof long[] longs) {
					return Arrays.toString(longs);
				}
				if (obj instanceof float[] floats) {
					return Arrays.toString(floats);
				}
				if (obj instanceof double[] doubles) {
					return Arrays.toString(doubles);
				}
			}
			return Arrays.deepToString((Object[]) obj);
		}

		// else
		String result = obj.toString();
		return result != null ? result : "null";
	}
	catch (Throwable throwable) {
		UnrecoverableExceptions.rethrowIfUnrecoverable(throwable);

		return defaultToString(obj);
	}
}

public ChannelFuture removeAndWriteAll() {
    assert executor.inEventLoop();

    if (isEmpty()) {
        return null;
    }

    ChannelPromise p = invoker.newPromise();
    PromiseCombiner combiner = new PromiseCombiner(executor);
    try {
        // It is possible for some of the written promises to trigger more writes. The new writes
        // will "revive" the queue, so we need to write them up until the queue is empty.
        for (PendingWrite write = head; write != null; write = head) {
            head = tail = null;
            size = 0;
            bytes = 0;

            while (write != null) {
                PendingWrite next = write.next;
                Object msg = write.msg;
                ChannelPromise promise = write.promise;
                recycle(write, false);
                if (!(promise instanceof VoidChannelPromise)) {
                    combiner.add(promise);
                }
                invoker.write(msg, promise);
                write = next;
            }
        }
        combiner.finish(p);
    } catch (Throwable cause) {
        p.setFailure(cause);
    }
    assertEmpty();
    return p;
}

public void channelRead(ChannelHandlerContext ctx, Object msg) {
    final Channel child = (Channel) msg;

    child.pipeline().addLast(childHandler);

    try {
        setChannelOptions(child, childOptions, logger);
    } catch (Throwable cause) {
        forceClose(child, cause);
        return;
    }
    setAttributes(child, childAttrs);

    if (!extensions.isEmpty()) {
        for (ChannelInitializerExtension extension : extensions) {
            try {
                extension.postInitializeServerChildChannel(child);
            } catch (Exception e) {
                logger.warn("Exception thrown from postInitializeServerChildChannel", e);
            }
        }
    }

    try {
        childGroup.register(child).addListener(future -> {
            if (!future.isSuccess()) {
                forceClose(child, future.cause());
            }
        });
    } catch (Throwable t) {
        forceClose(child, t);
    }
}

internal fun getResponseWithInterceptorChain(): Response {
  // Build a full stack of interceptors.
  val interceptors = mutableListOf<Interceptor>()
  interceptors += client.interceptors
  interceptors += RetryAndFollowUpInterceptor()
  interceptors += BridgeInterceptor()
  interceptors += CacheInterceptor()
  interceptors += ConnectInterceptor
  if (!forWebSocket) {
    interceptors += client.networkInterceptors
  }
  interceptors += CallServerInterceptor

  val chain =
    RealInterceptorChain(
      call = this,
      interceptors = interceptors,
      index = 0,
      exchange = null,
      request = originalRequest,
    )

  var calledNoMoreExchanges = false
  try {
    val response = chain.proceed(originalRequest)
    if (isCanceled()) {
      response.closeQuietly()
      throw IOException("Canceled")
    }
    return response
  } catch (e: IOException) {
    calledNoMoreExchanges = true
    throw noMoreExchanges(e) as Throwable
  } finally {
    if (!calledNoMoreExchanges) {
      noMoreExchanges(null)
    }
  }
}

override fun run() {
  threadName("OkHttp ${redactedUrl()}") {
    var signalledCallback = false
    timeout.enter()
    try {
      val response = getResponseWithInterceptorChain()
      signalledCallback = true
      responseCallback.onResponse(this@RealCall, response)
    } catch (e: IOException) {
      if (signalledCallback) {
        // Do not signal the callback twice!
        Platform.get().log("Callback failure for ${toLoggableString()}", Platform.INFO, e)
      } else {
        responseCallback.onFailure(this@RealCall, e)
      }
    } catch (t: Throwable) {
      cancel()
      if (!signalledCallback) {
        val canceledException = IOException("canceled due to $t")
        canceledException.initCause(t)
        responseCallback.onFailure(this@RealCall, canceledException)
      }
      if (t is InterruptedException) {
        Thread.currentThread().interrupt()
      } else {
        throw t
      }
    } finally {
      client.dispatcher.finished(this)
    }
  }
}

override fun connectTcp(): ConnectResult {
  check(rawSocket == null) { "TCP already connected" }

  var success = false

  // Tell the call about the connecting call so async cancels work.
  call.plansToCancel += this
  try {
    call.eventListener.connectStart(call, route.socketAddress, route.proxy)
    connectionPool.connectionListener.connectStart(route, call)

    connectSocket()
    success = true
    return ConnectResult(plan = this)
  } catch (e: IOException) {
    // If we used the ProxySelector, and got a IOException during connect, report the failure.
    if (route.address.proxy == null && route.proxy.type() != Proxy.Type.DIRECT) {
      route.address.proxySelector.connectFailed(
        route.address.url.toUri(),
        route.proxy.address(),
        e,
      )
    }
    call.eventListener.connectFailed(call, route.socketAddress, route.proxy, null, e)
    connectionPool.connectionListener.connectFailed(route, call, e)
    return ConnectResult(plan = this, throwable = e)
  } finally {
    call.plansToCancel -= this
    if (!success) {
      rawSocket?.closeQuietly()
    }
  }
}

private void validateServiceInterface(Class<?> service) {
  if (!service.isInterface()) {
    throw new IllegalArgumentException("API declarations must be interfaces.");
  }

  Deque<Class<?>> check = new ArrayDeque<>(1);
  check.add(service);
  while (!check.isEmpty()) {
    Class<?> candidate = check.removeFirst();
    if (candidate.getTypeParameters().length != 0) {
      StringBuilder message =
          new StringBuilder("Type parameters are unsupported on ").append(candidate.getName());
      if (candidate != service) {
        message.append(" which is an interface of ").append(service.getName());
      }
      throw new IllegalArgumentException(message.toString());
    }
    Collections.addAll(check, candidate.getInterfaces());
  }

  if (validateEagerly) {
    Reflection reflection = Platform.reflection;
    for (Method method : service.getDeclaredMethods()) {
      if (!reflection.isDefaultMethod(method)
          && !Modifier.isStatic(method.getModifiers())
          && !method.isSynthetic()) {
        loadServiceMethod(service, method);
      }
    }
  }
}

@Override
  public @Nullable CallAdapter<?, ?> get(
      Type returnType, Annotation[] annotations, Retrofit retrofit) {
    if (getRawType(returnType) != Call.class) {
      return null;
    }
    if (!(returnType instanceof ParameterizedType)) {
      throw new IllegalArgumentException(
          "Call return type must be parameterized as Call<Foo> or Call<? extends Foo>");
    }
    final Type responseType = Utils.getParameterUpperBound(0, (ParameterizedType) returnType);

    final Executor executor =
        Utils.isAnnotationPresent(annotations, SkipCallbackExecutor.class)
            ? null
            : callbackExecutor;

    return new CallAdapter<Object, Call<?>>() {
      @Override
      public Type responseType() {
        return responseType;
      }

      @Override
      public Call<Object> adapt(Call<Object> call) {
        return executor == null ? call : new ExecutorCallbackCall<>(executor, call);
      }
    };
  }

private void parseHttpMethodAndPath(String httpMethod, String value, boolean hasBody) {
  if (this.httpMethod != null) {
    throw methodError(
        method,
        "Only one HTTP method is allowed. Found: %s and %s.",
        this.httpMethod,
        httpMethod);
  }
  this.httpMethod = httpMethod;
  this.hasBody = hasBody;

  if (value.isEmpty()) {
    return;
  }

  // Get the relative URL path and existing query string, if present.
  int question = value.indexOf('?');
  if (question != -1 && question < value.length() - 1) {
    // Ensure the query string does not have any named parameters.
    String queryParams = value.substring(question + 1);
    Matcher queryParamMatcher = PARAM_URL_REGEX.matcher(queryParams);
    if (queryParamMatcher.find()) {
      throw methodError(
          method,
          "URL query string \"%s\" must not have replace block. "
              + "For dynamic query parameters use @Query.",
          queryParams);
    }
  }

  this.relativeUrl = value;
  this.relativeUrlParamNames = parsePathParameters(value);
}

@IgnoreJRERequirement
  private static final class BodyCallAdapter<R> implements CallAdapter<R, CompletableFuture<R>> {
    private final Type responseType;

    BodyCallAdapter(Type responseType) {
      this.responseType = responseType;
    }

    @Override
    public Type responseType() {
      return responseType;
    }

    @Override
    public CompletableFuture<R> adapt(final Call<R> call) {
      CompletableFuture<R> future = new CallCancelCompletableFuture<>(call);
      call.enqueue(new BodyCallback(future));
      return future;
    }

    @IgnoreJRERequirement
    private class BodyCallback implements Callback<R> {
      private final CompletableFuture<R> future;

      public BodyCallback(CompletableFuture<R> future) {
        this.future = future;
      }

      @Override
      public void onResponse(Call<R> call, Response<R> response) {
        if (response.isSuccessful()) {
          future.complete(response.body());
        } else {
          future.completeExceptionally(new HttpException(response));
        }
      }

      @Override
      public void onFailure(Call<R> call, Throwable t) {
        future.completeExceptionally(t);
      }
    }
  }

@Override
    public Object apply(Object o) {
        if (o == null || o instanceof BigDecimal) {
            return o;
        }

        if (o instanceof Boolean) {
            return (Boolean) o ? BigDecimal.ONE : BigDecimal.ZERO;
        }

        if (o instanceof Byte
                || o instanceof Short
                || o instanceof Integer
                || o instanceof Long
                || o instanceof AtomicInteger
                || o instanceof AtomicLong
        ) {
            return BigDecimal.valueOf(((Number) o).longValue());
        }

        if (o instanceof Float || o instanceof Double) {
            double doubleValue = ((Number) o).doubleValue();
            return toBigDecimal(doubleValue);
        }

        if (o instanceof BigInteger) {
            return new BigDecimal((BigInteger) o);
        }

        if (o instanceof String) {
            return new BigDecimal((String) o);
        }

        throw new JSONException("can not cast to BigDecimal " + o.getClass());
    }

@SuppressWarnings("unchecked")
    static <T> T parseObject(
            String text,
            Class<T> clazz,
            Filter filter,
            JSONReader.Feature... features
    ) {
        if (text == null || text.isEmpty()) {
            return null;
        }

        final JSONReader.Context context = JSONFactory.createReadContext(filter, features);
        boolean fieldBased = (context.features & JSONReader.Feature.FieldBased.mask) != 0;
        ObjectReader<T> objectReader = context.provider.getObjectReader(clazz, fieldBased);

        try (JSONReader reader = JSONReader.of(text, context)) {
            if (reader.nextIfNull()) {
                return null;
            }

            T object = objectReader.readObject(reader, clazz, null, 0);
            if (reader.resolveTasks != null) {
                reader.handleResolveTasks(object);
            }
            if (reader.ch != EOI && (context.features & IgnoreCheckClose.mask) == 0) {
                throw new JSONException(reader.info("input not end"));
            }
            return object;
        }
    }

