            }
            if (reader.ch != EOI && (context.features & IgnoreCheckClose.mask) == 0) {
                throw new JSONException(reader.info("input not end"));
            }
            return object;
        }
    }

@SuppressWarnings({"unchecked", "rawtypes"})
    public JSONObject getJSONObject(int index) {
        Object value = get(index);

        if (value == null) {
            return null;
        }

        if (value instanceof JSONObject) {
            return (JSONObject) value;
        }

        if (value instanceof String) {
            String str = (String) value;

            if (str.isEmpty() || "null".equalsIgnoreCase(str)) {
                return null;
            }

            JSONReader reader = JSONReader.of(str);
            return JSONFactory.OBJECT_READER.readObject(reader, null, null, 0);
        }

        if (value instanceof Map) {
            JSONObject object = new JSONObject((Map) value);
            set(index, object);
            return object;
        }

        Class valueClass = value.getClass();
        ObjectWriter objectWriter = JSONFactory.getDefaultObjectWriterProvider().getObjectWriter(valueClass);

        JSONObject jsonObject = (objectWriter instanceof ObjectWriterAdapter)
                ? ((ObjectWriterAdapter) objectWriter).toJSONObject(value)
                : (JSONObject) JSON.toJSON(value);

        set(index, jsonObject);
        return jsonObject;
    }

@SuppressWarnings({"unchecked", "rawtypes"})
    public JSONObject getJSONObject(String key) {
        Object value = super.get(key);

        if (value == null) {
            return null;
        }

        if (value instanceof JSONObject) {
            return (JSONObject) value;
        }

        if (value instanceof String) {
            String str = (String) value;

            if (str.isEmpty() || "null".equalsIgnoreCase(str)) {
                return null;
            }

            JSONReader reader = JSONReader.of(str);
            return JSONFactory.OBJECT_READER.readObject(reader, null, null, 0);
        }

        if (value instanceof Map) {
            JSONObject object = new JSONObject((Map) value);
            put(key, object);
            return object;
        }

        Class valueClass = value.getClass();
        ObjectWriter objectWriter = JSONFactory.getDefaultObjectWriterProvider().getObjectWriter(valueClass);
        if (objectWriter instanceof ObjectWriterAdapter) {
            ObjectWriterAdapter writerAdapter = (ObjectWriterAdapter) objectWriter;
            JSONObject jsonObject = writerAdapter.toJSONObject(value);
            put(key, jsonObject);
            return jsonObject;
        }

        return null;
    }

@SuppressWarnings({ "rawtypes", "unchecked" })
    static void nameFilter(Map map, NameFilter nameFilter) {
        JSONObject changed = null;
        for (Iterator<?> it = map.entrySet().iterator(); it.hasNext(); ) {
            Map.Entry entry = (Map.Entry) it.next();
            Object entryKey = entry.getKey();
            Object entryValue = entry.getValue();

            if (entryValue instanceof JSONObject) {
                ((JSONObject) entryValue).nameFilter(nameFilter);
            } else if (entryValue instanceof Iterable) {
                nameFilter((Iterable<?>) entryValue, nameFilter);
            }

            if (entryKey instanceof String) {
                String key = (String) entryKey;
                String processName = nameFilter.process(map, key, entryValue);
                if (processName != null && !processName.equals(key)) {
                    if (changed == null) {
                        changed = new JSONObject();
                    }
                    changed.put(processName, entryValue);
                    it.remove();
                }
            }
        }
        if (changed != null) {
            map.putAll(changed);
        }
    }

@Override
        public boolean apply(Object fieldValue) {
            if (fieldValue == null) {
                return false;
            }

            Double fieldValueDouble;

            if (fieldValue instanceof Boolean) {
                fieldValueDouble = (Boolean) fieldValue ? 1D : 0D;
            } else if (fieldValue instanceof Number) {
                fieldValueDouble = ((Number) fieldValue).doubleValue();
            } else {
                throw new UnsupportedOperationException();
            }

            int cmp = fieldValueDouble.compareTo(value);
            switch (operator) {
                case LT:
                    return cmp < 0;
                case LE:
                    return cmp <= 0;
                case EQ:
                    return cmp == 0;
                case NE:
                    return cmp != 0;
                case GT:
                    return cmp > 0;
                case GE:
                    return cmp >= 0;
                default:
                    throw new UnsupportedOperationException();
            }
        }

@Override
        public boolean apply(Object fieldValue) {
            if (!(fieldValue instanceof String)) {
                return false;
            }

            String fieldValueStr = ((String) fieldValue);
            if (operator == Operator.STARTS_WITH) {
                return fieldValueStr.startsWith(value);
            }
            if (operator == Operator.ENDS_WITH) {
                return fieldValueStr.endsWith(value);
            }

            int cmp = fieldValueStr.compareTo(this.value);

            switch (operator) {
                case LT:
                    return cmp < 0;
                case LE:
                    return cmp <= 0;
                case EQ:
                    return cmp == 0;
                case NE:
                    return cmp != 0;
                case GT:
                    return cmp > 0;
                case GE:
                    return cmp >= 0;
                default:
                    throw new UnsupportedOperationException();
            }
        }

@Override
        boolean apply(Object arg) {
            if (!(arg instanceof String)) {
                return false;
            }

            String fieldValue = (String) arg;
            if (fieldValue.length() < minLength) {
                return not;
            }

            int start = 0;
            if (startsWithValue != null) {
                if (!fieldValue.startsWith(startsWithValue)) {
                    return not;
                }
                start += startsWithValue.length();
            }

            if (containsValues != null) {
                for (String containsValue : containsValues) {
                    int index = fieldValue.indexOf(containsValue, start);
                    if (index == -1) {
                        return not;
                    }
                    start = index + containsValue.length();
                }
            }

            if (endsWithValue != null) {
                if (!fieldValue.endsWith(endsWithValue)) {
                    return not;
                }
            }

            return !not;
        }

@Override
    public JSONPath getParent() {
        int size = segments.size();
        if (size == 0) {
            return null;
        }

        if (size == 1) {
            return RootPath.INSTANCE;
        }

        if (size == 2) {
            return JSONPathSingle.of(segments.get(0));
        }

        StringBuilder buf = new StringBuilder();
        buf.append('$');
        List<JSONPathSegment> parentSegments = new ArrayList<>(size - 1);
        for (int i = 0, end = size - 1; i < end; i++) {
            JSONPathSegment segment = segments.get(i);
            parentSegments.add(segment);
            boolean array = segment instanceof JSONPathSegmentIndex
                    || segment instanceof JSONPathSegment.MultiIndexSegment
                    || segment instanceof JSONPathFilter;
            if (!array) {
                buf.append('.');
            }
            buf.append(segment);
        }

        String parentPath = buf.toString();
        if (size == 3) {
            new JSONPathTwoSegment(parentPath, segments.get(0), segments.get(1));
        }

        return new JSONPathMulti(parentPath, parentSegments);
    }

@Override
    public String extractScalar(JSONReader jsonReader) {
        int size = segments.size();
        if (size == 0) {
            return null;
        }

        boolean eval = false;
        Context context = null;
        for (int i = 0; i < size; i++) {
            JSONPathSegment segment = segments.get(i);
            JSONPathSegment nextSegment = null;

            int nextIndex = i + 1;
            if (nextIndex < size) {
                nextSegment = segments.get(nextIndex);
            }

            context = new Context(this, context, segment, nextSegment, 0);
            if (eval) {
                segment.eval(context);
            } else {
                segment.accept(jsonReader, context);
            }

            if (context.eval) {
                eval = true;
                if (context.value == null) {
                    break;
                }
            }
        }

        return JSON.toJSONString(context.value);
    }

@Override
        public boolean remove(JSONPath.Context context) {
            Object object = context.parent == null
                    ? context.root
                    : context.parent.value;

            int removeCount = 0;
            if (object instanceof Map) {
                Map map = (Map) object;
                for (String name : names) {
                    if (map.remove(name) != null) {
                        removeCount++;
                    }
                }
                return removeCount > 0;
            }

            ObjectReaderProvider provider = context.path.getReaderContext().provider;
            ObjectReader objectReader = provider.getObjectReader(object.getClass());

            if (objectReader instanceof ObjectReaderBean) {
                for (long nameHash : nameHashCodes) {
                    FieldReader fieldReader = objectReader.getFieldReader(nameHash);
                    if (fieldReader == null) {
                        continue;
                    }
                    fieldReader.accept(object, null);
                    removeCount++;
                }
                return removeCount > 0;
            }

            throw new JSONException("UnsupportedOperation " + getClass());
        }

@Override
    public void setCallback(Object object, BiFunction callback) {
        if (object instanceof Map) {
            Map map = (Map) object;
            Object originValue = map.get(name);
            if (originValue != null || map.containsKey(name)) {
                map.put(name, callback.apply(map, originValue));
            }
            return;
        }

        Class<?> objectClass = object.getClass();

        if (readerContext == null) {
            readerContext = JSONFactory.createReadContext();
        }
        FieldReader fieldReader = readerContext.provider
                .getObjectReader(objectClass)
                .getFieldReader(nameHashCode);

        if (writerContext == null) {
            writerContext = JSONFactory.createWriteContext();
        }
        FieldWriter fieldWriter = writerContext.provider
                .getObjectWriter(objectClass)
                .getFieldWriter(nameHashCode);

        if (fieldReader != null && fieldWriter != null) {
            Object fieldValue = fieldWriter.getFieldValue(object);
            Object value = callback.apply(object, fieldValue);
            fieldReader.accept(object, value);
        }
    }

@Override
    public void accept(T object, Object value) {
        String fieldValue;
        if (value instanceof String || value == null) {
            fieldValue = (String) value;
        } else {
            fieldValue = value.toString();
        }

        if (fieldValue != null) {
            if (trim) {
                fieldValue = fieldValue.trim();
            }
            if (upper) {
                fieldValue = fieldValue.toUpperCase();
            }
            if (emptyToNull && fieldValue.isEmpty()) {
                fieldValue = null;
            }
        }

        if (schema != null) {
            schema.assertValidate(fieldValue);
        }

        try {
            propertyAccessor.setObject(object, fieldValue);
        } catch (Exception e) {
            if (e instanceof JSONException) {
                throw e;
            }
            throw new JSONException("set " + fieldName + " error", e);
        }
    }
